@media (prefers-reduced-motion: reduce) {
  .dmx-dot,
  .dmx-ripple,
  .dmx-ripple-echo,
  .dmx-center-origin-ripple,
  .dmx-collapse,
  .dmx-hover-ripple,
  .dmx-path,
  .dmx-diagonal-alt-sweep,
  .dmx-spiral-snake,
  .dmx-diagonal-snake,
  .dmx-outer-snake,
  .dmx-middle-snake {
    animation: none !important;
    transition: none !important;
  }
}
